private List<String> getLeastOperatorsFromMap(Map<String, Integer> operatorTicketNum){
    if (operatorTicketNum == null || operatorTicketNum.isEmpty()) {
        return Collections.emptyList();
    }

    // 遍历找到map中的最小值
    int leastNum = Integer.MAX_VALUE;
    List<String> leastOperators = new ArrayList<>();
    for (Map.Entry<String, Integer> entry : operatorTicketNum.entrySet()) {
        Integer curNum = entry.getValue();
        if (curNum == null) {
            qcLog.warn("getLeastOperatorsFromMap: value is null");
            continue;
        }
        if (curNum < leastNum) {
            leastNum = curNum;
            leastOperators.clear();
            leastOperators.add(entry.getKey());
        } else if (curNum == leastNum) {
            leastOperators.add(entry.getKey());
        }
    }
    return leastOperators;
}
```
该代码合并了两次循环，而且只返回 List，不会返回 null。此外，如果 value 值为 null，不需要向日志中打印异常信息。

