private void DrawLineInAutoCAD(double x1, double y1, double x2, double y2)
{
    Document acDoc = Application.DocumentManager.MdiActiveDocument;
    Database acDb = acDoc.Database;

    using (var tr = acDb.TransactionManager.StartTransaction())
    {
        BlockTable acBlkTbl;
        acBlkTbl = tr.GetObject(acDb.BlockTableId, OpenMode.ForRead) as BlockTable;

        BlockTableRecord acBlkTblRec;
        acBlkTblRec = tr.GetObject(acBlkTbl[BlockTableRecord.ModelSpace], OpenMode.ForWrite) as BlockTableRecord;

        using (var line = new Line(new Point3d(x1, y1, 0), new Point3d(x2, y2, 0)))
        {
            acBlkTblRec.AppendEntity(line);
            tr.AddNewlyCreatedDBObject(line, true);
        }

        tr.Commit();
    }
}
```

